// Mapea language a country_code de Ahrefs y prepara contexto compartido.
// IMPORTANTE: el payload real de n8n A usa db_record.main_keyword y db_record.language (no target_keyword/locale).
// NO usar brief_final.brand_contract.brand_slug — tiene bug de cross-contamination conocido.
const LANG_TO_COUNTRY = {
  'en': 'us',
  'pt': 'br',
  'es': 'mx'
};
const LOCALE_TO_COUNTRY = {
  'es-MX': 'mx', 'es-ES': 'es', 'es-AR': 'ar', 'es-CO': 'co',
  'pt-BR': 'br', 'pt-PT': 'pt',
  'en-US': 'us', 'en-GB': 'gb', 'en-CA': 'ca'
};

const item = $input.first().json;
const dbRec = item.db_record || {};

// Keyword: db_record.main_keyword es el campo correcto en el payload real
const keyword = dbRec.main_keyword
  || item.target_keyword
  || item.keyword
  || (item.brief_data && item.brief_data.target_keyword);

// Language: db_record.language = 'en' | 'pt' | 'es' (ISO 639-1)
const lang = (dbRec.language || '').toLowerCase();
const locale = item.locale || '';
const country = LANG_TO_COUNTRY[lang] || LOCALE_TO_COUNTRY[locale] || 'us';

// Brand slug: desde db_record (fuente confiable, brief_final.brand_contract puede tener cross-contamination)
const brand_slug = dbRec.brand_slug || item.brand_slug || '';

// Content item ID: ID de la fila content_items que originó este workflow
const content_item_id = dbRec.id || dbRec.content_item_id || item.id || item.content_item_id;

if (!keyword) {
  throw new Error('No keyword encontrada en db_record.main_keyword ni en fallbacks — abortando bloque Ahrefs');
}

return [{
  json: {
    ...item,
    _ahrefs_ctx: {
      keyword,
      country,
      lang,
      content_item_id,
      brand_slug
    }
  }
}];

// Normaliza la respuesta Ahrefs y construye el bloque ahrefs_research.
// Filtra dominios de competidores prohibidos del SERP.
// Si una llamada Ahrefs falló (continueOnFail), el campo queda null y se loguea.

const COMPETIDORES_PROHIBIDOS_DOMAINS = [
  // pt-BR iGaming (16) — debe sincronizarse con competidores-prohibidos.yaml
  'bet365.com', 'betano.com.br', 'sportingbet.com', 'pixbet.com',
  'betfair.com', 'rivalo.com', 'parimatch.com', 'kto.com',
  'galera.bet', 'estrelabet.com', 'esporte.net.br', 'betnacional.com',
  '1xbet.com', 'stake.com', 'sportingbet.com', 'betsbola.com'
];

function isCompetitor(url) {
  if (!url) return false;
  return COMPETIDORES_PROHIBIDOS_DOMAINS.some(d => url.toLowerCase().includes(d));
}

function safeArr(x) { return Array.isArray(x) ? x : []; }

// Cada item recibido viene de un nodo HTTP distinto (merge combineAll los une)
const items = $input.all();
const data = items.reduce((acc, it) => ({ ...acc, ...it.json }), {});

// La estructura exacta depende de la API de Ahrefs v3. Adaptar si difiere.
// Asumimos que cada respuesta tiene un campo principal por endpoint.
const overview = data.overview || data.keyword_overview || (data.keywords && data.keywords[0]) || {};
const serpRaw  = data.serp_overview || data.positions || [];
const questions= safeArr(data.questions || data.matching_terms);
const related  = safeArr(data.related_terms);
const alsoRank = safeArr(data.also_rank_for);

const ctx = data._ahrefs_ctx || {};

// 1. Filtrar competidores del SERP
const serpFiltered = safeArr(serpRaw).filter(r => !isCompetitor(r.url || r.target_url));

// 2. Benchmarks SERP
const totalSerp = serpFiltered.length || 1;
const withFaq   = serpFiltered.filter(r => r.has_schema_faq || r.has_faq).length;
const withTable = serpFiltered.filter(r => r.has_table).length;
const hasFs     = serpFiltered.some(r => r.has_featured_snippet);
const avgWords  = Math.round(serpFiltered.reduce((s, r) => s + (r.word_count || 0), 0) / totalSerp);
const avgH2     = Math.round(serpFiltered.reduce((s, r) => s + (r.h2_count || 0), 0) / totalSerp);

// Tipo de contenido dominante
const typeCount = serpFiltered.reduce((acc, r) => {
  const t = r.content_type || 'unknown';
  acc[t] = (acc[t] || 0) + 1;
  return acc;
}, {});
const dominantType = Object.entries(typeCount).sort((a, b) => b[1] - a[1])[0]?.[0] || 'unknown';

// 3. FAQ priorizadas por volumen, top 8
const faqTop = questions
  .sort((a, b) => (b.volume || 0) - (a.volume || 0))
  .slice(0, 8)
  .map(q => ({ question: q.keyword, volume: q.volume || 0 }));

// 4. LSI: KD < 30 y volumen > 100, top 15
const lsiTop = related
  .filter(k => (k.keyword_difficulty || 99) < 30 && (k.volume || 0) > 100)
  .sort((a, b) => (b.volume || 0) - (a.volume || 0))
  .slice(0, 15)
  .map(k => ({ keyword: k.keyword, volume: k.volume || 0, kd: k.keyword_difficulty || null }));

// 5. Also rank for top 10
const alsoTop = alsoRank
  .sort((a, b) => (b.volume || 0) - (a.volume || 0))
  .slice(0, 10)
  .map(k => ({ keyword: k.keyword, volume: k.volume || 0 }));

const ahrefs_research = {
  keyword_metrics: {
    volume: overview.volume || null,
    traffic_potential: overview.traffic_potential || null,
    keyword_difficulty: overview.keyword_difficulty || null,
    cpc: overview.cpc || null,
    global_volume: overview.global_volume || null,
    parent_topic: overview.parent_topic || null,
    search_intent: overview.search_intent || null
  },
  serp_benchmarks: {
    avg_word_count: avgWords || null,
    avg_h2_count: avgH2 || null,
    pct_with_faq: totalSerp ? +(withFaq / totalSerp).toFixed(2) : null,
    pct_with_tables: totalSerp ? +(withTable / totalSerp).toFixed(2) : null,
    dominant_content_type: dominantType,
    has_featured_snippet: hasFs,
    serp_top3_titles: serpFiltered.slice(0, 3).map(r => r.title).filter(Boolean),
    competitors_filtered_out: safeArr(serpRaw).length - serpFiltered.length
  },
  recommended_structure: {
    target_word_count: avgWords || 1500,
    suggested_h2_count: avgH2 || 5,
    faq_required: totalSerp ? (withFaq / totalSerp) >= 0.6 : true,
    table_recommended: totalSerp ? (withTable / totalSerp) >= 0.5 : false,
    featured_snippet_target: hasFs
  },
  faq_questions: faqTop,
  lsi_keywords: lsiTop,
  also_rank_for: alsoTop,
  data_fetched_at: new Date().toISOString(),
  ahrefs_credits_used: 5,
  ahrefs_partial_failure: !overview.volume || serpFiltered.length === 0
};

return [{
  json: {
    content_item_id: ctx.content_item_id,
    brand_slug: ctx.brand_slug,
    keyword: ctx.keyword,
    ahrefs_research
  }
}];
